#include <bits/stdc++.h>
using namespace std;

const int N=1e5+5;
const double eps=1e-6;

struct Node{
    long long a,b;
    Node operator+(Node y){
        return {a+y.a,b+y.b};
    }
}f[N][18][2];
int n,m,a[N],b[N],p[N][18][2];
long long h[N];

inline int read(void)
{
    int res = 0, f = 1; char ch = getchar();
    while (!isdigit(ch)) { if (ch == '-') f = -1; ch = getchar(); }
    while (isdigit(ch)) { res = res * 10 + ch - '0'; ch = getchar(); }
    return res * f;
}

int cmp(double x,double y){
    if(fabs(x-y)<=eps)
        return 0;
    if(x<y)
        return -1;
    return 1;
}

long long d(int x,int y){
    if(!x || !y)
        return 0;
    return abs(h[x]-h[y]);
}

void set_path(){
    vector<int> g(n);
    g[0]=n;
    for(int i=n-1;i;i--){
        int l=0,r=n-i-1;
        while(l<r){
            int mid=(l+r+1)/2;
            if(h[g[mid]]<h[i])
                l=mid;
            else
                r=mid-1;
        }
        if(i==n-1)
            b[i]=n;
        else{
            if(l==n-i-1)
                b[i]=g[l],a[i]=g[l-1];
            else if(d(i,g[l])<=d(i,g[l+1])){
                b[i]=g[l];
                if(l==0)
                    a[i]=g[l+1];
                else if(d(i,g[l-1])<=d(i,g[l+1]))
                    a[i]=g[l-1];
                else
                    a[i]=g[l+1];
            }else{
                b[i]=g[l+1];
                if(d(i,g[l])<=d(i,g[l+2]))
                    a[i]=g[l];
                else
                    a[i]=g[l+2];
            }
        }
        if(h[g[l]]<h[i])
            g.insert(g.begin()+l+1,i);
        else
            g.insert(g.begin(),i);
    }

    for(int i=n;i;i--){
        p[i][0][0]=a[i],p[i][0][1]=b[i];
        f[i][0][0]={d(i,a[i]),0},f[i][0][1]={0,d(i,b[i])};
        for(int j=1;j<18;j++){
            p[i][j][0]=p[p[i][j-1][0]][j-1][j==1];
            p[i][j][1]=p[p[i][j-1][1]][j-1][j>1];
            if(p[i][j][0])
                f[i][j][0]=f[i][j-1][0]+f[p[i][j-1][0]][j-1][j==1];
            if(p[i][j][1])
                f[i][j][1]=f[i][j-1][1]+f[p[i][j-1][1]][j-1][j>1];
            if(!p[i][j][0] && !p[i][j][1])
                break;
        }
    }
}

Node solve(int s,int x){
    Node sum={0,0};
    int pl=s;
    for(int i=17;i>=0;i--)
        if(p[pl][i][0] && sum.a+sum.b+f[pl][i][0].a+f[pl][i][0].b<=x)
            sum=sum+f[pl][i][0],pl=p[pl][i][0];
    return sum;
}

int main(){
    h[0]=-1e16;
    n=read();
    for(int i=1;i<=n;i++)
        h[i]=read();
    set_path();

    int s,x;
    x=read();
    double ans=1e16;
    for(int i=1;i<=n;i++){
        Node tmp=solve(i,x);
        if(tmp.b==0){
            if(ans==1e16)
                s=i;
        }else if(cmp(1.0*tmp.a/tmp.b,ans)==-1 || !cmp(1.0*tmp.a/tmp.b,ans) && h[i]>h[s])
            s=i,ans=1.0*tmp.a/tmp.b;

    }
    printf("%d\n",s);

    m=read();
    while(m--){
        s=read(),x=read();
        Node tmp=solve(s,x);
        printf("%lld %lld\n",tmp.a,tmp.b);
    }
    return 0;
}
